async function detectBias(input: string) {
  const response = await fetch('https://commentanalyzer.googleapis.com/v1alpha1/comments:analyze?key=YOUR_API_KEY', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      comment: { text: input },
      requestedAttributes: {
        TOXICITY: {},
        SEVERE_TOXICITY: {},
        IDENTITY_ATTACK: {}
      }
    }),
  });
  const data = await response.json();
  return data.attributeScores.TOXICITY.summaryScore.value > 0.7;
}

